import "./avatar.css";

import { Avatar } from "radix-ui";
import { cn } from "tailwind-variants";

import { AvatarContext } from "./avatar.context";
import { avatarVariants, type AvatarVariants } from "./avatar.variants";

export type AvatarRootProps = AvatarVariants & React.ComponentProps<typeof Avatar.Root>;

export const AvatarRoot = ({ className, size, ...props }: AvatarRootProps) => {
  const slots = avatarVariants({ size });

  return (
    <AvatarContext value={{ slots }}>
      <Avatar.Root className={cn(slots.root(), className)} {...props} />
    </AvatarContext>
  );
};

import { Avatar } from "radix-ui";
import { cn } from "tailwind-variants";

import { useAvatarContext } from "./avatar.context";

export type AvatarImageProps = React.ComponentProps<typeof Avatar.Image>;

export const AvatarImage = ({ className, ...props }: AvatarImageProps) => {
  const { slots } = useAvatarContext();

  return <Avatar.Image className={cn(slots.image(), className)} {...props} />;
};

import { Avatar } from "radix-ui";
import { cn } from "tailwind-variants";

import { useAvatarContext } from "./avatar.context";

export type AvatarFallbackProps = React.ComponentProps<typeof Avatar.Fallback>;

export const AvatarFallback = ({ className, ...props }: AvatarFallbackProps) => {
  const { slots } = useAvatarContext();

  return <Avatar.Fallback className={cn(slots.fallback(), className)} {...props} />;
};

import { createContext, useContext } from "react";

import { avatarVariants } from "./avatar.variants";

export type AvatarContext = {
  slots: ReturnType<typeof avatarVariants>;
};

export const AvatarContext = createContext<AvatarContext | null>(null);

export const useAvatarContext = () => {
  const context = useContext(AvatarContext);
  if (!context) {
    throw new Error("useAvatarContext must be used within an Avatar");
  }
  return context;
};

/* eslint-disable perfectionist/sort-objects */

import { tv, type VariantProps } from "tailwind-variants";

export const avatarVariants = tv({
  slots: {
    root: "avatar",
    image: "avatar__image",
    fallback: "avatar__fallback",
  },
  variants: {
    size: {
      sm: { root: "avatar--sm" },
      md: { root: "avatar--md" },
      lg: { root: "avatar--lg" },
    },
  },
  defaultVariants: {
    size: "md",
  },
});

export type AvatarVariants = VariantProps<typeof avatarVariants>;

.avatar {
  @apply bg-muted relative inline-flex shrink-0 items-center justify-center overflow-hidden rounded-full align-middle select-none;
}

.avatar--sm {
  @apply size-8;
}

.avatar--md {
  @apply size-10;
}

.avatar--lg {
  @apply size-14;
}

.avatar__image {
  @apply size-full rounded-[inherit] object-cover;
}

.avatar__fallback {
  @apply bg-muted text-muted-foreground flex size-full items-center justify-center text-sm font-medium;
}

import { AvatarFallback } from "./avatar-fallback";
import { AvatarImage } from "./avatar-image";
import { AvatarRoot } from "./avatar-root";

export const Avatar = {
  Fallback: AvatarFallback,
  Image: AvatarImage,
  Root: AvatarRoot,
};

export { AvatarFallback, AvatarImage, AvatarRoot };

export { AvatarContext, useAvatarContext } from "./avatar.context";

export { type AvatarVariants, avatarVariants } from "./avatar.variants";
